import requests
from datetime import datetime, timezone

def list_expiring_secrets(token: str, days_ahead: int = 30) -> list:
    """Find app registrations with secrets expiring within N days."""
    from datetime import timedelta
    cutoff = (datetime.now(timezone.utc) + timedelta(days=days_ahead)).isoformat()

    url = "https://graph.microsoft.com/v1.0/applications"
    params = {"$select": "displayName,appId,passwordCredentials,keyCredentials", "$top": 999}
    headers = {"Authorization": f"Bearer {token}"}
    expiring = []
    while url:
        r = requests.get(url, headers=headers, params=params)
        data = r.json()
        for app in data.get("value", []):
            for cred in app.get("passwordCredentials", []):
                end_dt = cred.get("endDateTime", "")
                if end_dt and end_dt <= cutoff:
                    expiring.append({
                        "app": app["displayName"],
                        "appId": app["appId"],
                        "hint": cred.get("hint", ""),
                        "expires": end_dt[:10]
                    })
        url = data.get("@odata.nextLink"); params = {}
    return sorted(expiring, key=lambda x: x["expires"])

expiring = list_expiring_secrets(access_token, days_ahead=30)
print(f"{len(expiring)} credentials expiring within 30 days:")
for e in expiring:
    print(f"  {e['app']:<40} hint={e['hint']:<8} expires={e['expires']}")

import requests

# List delegated permission grants for a service principal
SP_ID = "<service-principal-object-id>"

grants = requests.get(
    f"https://graph.microsoft.com/v1.0/servicePrincipals/{SP_ID}/oauth2PermissionGrants",
    headers={"Authorization": f"Bearer {access_token}"}
).json().get("value", [])

for g in grants:
    print(f"Resource: {g['resourceId']:<40} Scopes: {g['scope']}")

# List application role assignments (app permissions, not delegated)
app_assignments = requests.get(
    f"https://graph.microsoft.com/v1.0/servicePrincipals/{SP_ID}/appRoleAssignments",
    headers={"Authorization": f"Bearer {access_token}"}
).json().get("value", [])

for a in app_assignments:
    print(f"Resource SP: {a['resourceId']:<40} Role ID: {a['appRoleId']}")

# Revoke all consent grants for a service principal (emergency de-authorise)
for g in grants:
    requests.delete(
        f"https://graph.microsoft.com/v1.0/oauth2PermissionGrants/{g['id']}",
        headers={"Authorization": f"Bearer {access_token}"}
    )
    print(f"Revoked grant: {g['id']}")

import requests
from datetime import datetime, timedelta, timezone
import json

def credential_expiry_report(token: str) -> None:
    """Print all app credentials expiring in the next 30 days."""
    cutoff = (datetime.now(timezone.utc) + timedelta(days=30)).isoformat()
    HDR = {"Authorization": f"Bearer {token}"}

    url = "https://graph.microsoft.com/v1.0/applications"
    params = {"$select": "displayName,appId,passwordCredentials,keyCredentials", "$top": 999}
    report = []
    while url:
        r = requests.get(url, headers=HDR, params=params); data = r.json()
        for app in data.get("value", []):
            for cred in app.get("passwordCredentials", []) + app.get("keyCredentials", []):
                end = cred.get("endDateTime", "")
                if end and end <= cutoff:
                    days_left = (datetime.fromisoformat(end.rstrip("Z")).replace(tzinfo=timezone.utc)
                                 - datetime.now(timezone.utc)).days
                    report.append({
                        "app": app["displayName"],
                        "type": "secret" if "hint" in cred else "cert",
                        "expires": end[:10],
                        "days_left": days_left
                    })
        url = data.get("@odata.nextLink"); params = {}

    report.sort(key=lambda x: x["days_left"])
    print(f"{'App':<40} {'Type':<8} {'Expires':<12} {'Days Left':>9}")
    print("-" * 73)
    for r in report:
        flag = " *** URGENT ***" if r["days_left"] <= 7 else ""
        print(f"{r['app']:<40} {r['type']:<8} {r['expires']:<12} {r['days_left']:>9}{flag}")

credential_expiry_report(access_token)
